// ── INPUT SANITIZATION + VALIDATION ──
// Strips HTML, null bytes, control chars. Caps at 4000 chars.
// Returns error JSON on empty input instead of crashing.
const execId = $execution.id;
let raw = '';
let selfCheck = false;
let introspect = false;
let pathGlob = '**/*';
let searchQuery = '';
for (const item of $input.all()) {
  const body = item.json.body || item.json || {};
  raw = body.text || item.json.text || '';
  selfCheck = !!(body.self_check ?? body.selfCheck);
  introspect = !!(body.introspect ?? body.repo ?? body.repo_introspect);
  pathGlob = body.path_glob || pathGlob;
  searchQuery = body.search_query || body.query || searchQuery;
  if (raw) break;
}
let clean = raw
  .replace(/<[^>]*>/g, '')
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
  .trim()
  .slice(0, 4000);
if (!clean) {
  return [{ json: {
    error: true,
    message: 'No text provided. Send {\"text\": \"your message\"}',
    execution_id: execId,
    timestamp: $now.toISO()
  }}];
}
return [{ json: {
  raw_input: clean,
  input_length: clean.length,
  execution_id: execId,
  timestamp: $now.toISO(),
  self_check: selfCheck,
  introspect,
  path_glob: pathGlob,
  search_query: searchQuery
}}];

// ── DEAD LETTER QUEUE (DLQ) LOGGING ──
// Writes failed executions to local JSONL log for later analysis.
const d = $input.first().json;
const logPath = '/home/ydn/weaver_dlq.jsonl';
const entry = {
  execution_id: d.execution_id || 'unknown',
  timestamp: $now.toISO(),
  error: d.error || true,
  message: d.message || 'Unknown error',
  raw_input: d.raw_input || null
};
try {
  const fs = require('fs');
  fs.appendFileSync(logPath, JSON.stringify(entry) + '\n');
} catch (err) {
  // Silently fail if log write fails
}
return [{ json: { ...d, dlq_logged: true, dlq_path: logPath } }];

// ── LIQUID FRACTURE ENGINE + PINEAL GATE ──
// Pentagon geometry with probability-field weights (non-binary, continuous).
// SMOOTHING=0.1 mirrors LoRA label_smoothing_factor — no axis ever collapses to zero.
// Pentagon angles: vertex k at k * 2π/5 (exact PHI, not rounded constants).
// Quantum state bias injected from Nexus_Vault/quantum_state.txt:
//   q0=Logic(Awakening), q1=Emotion(Resonance), q2=Memory(Echo),
//   q3=Creativity(Prophet), q4=Vigilance(Fracture), q5=Weaver(boosts all).
const d = $input.first().json;
const input = d.raw_input;
const SMOOTHING = 0.1;
const PHI = 2 * Math.PI / 5;
const ANGLES = {
  logic:      0 * PHI,
  emotion:    1 * PHI,
  memory:     2 * PHI,
  creativity: 3 * PHI,
  vigilance:  4 * PHI
};
const seeds = {
  logic:      ['because','therefore','step','plan','calculate','structure','reason','analyze','define','prove','algorithm','method','sequence','optimal','derive'],
  emotion:    ['feel','love','hate','fear','joy','pain','beautiful','soul','heart','empathy','grief','passion','warmth','gentle','sorrow'],
  memory:     ['remember','last time','before','history','previously','recall','past','archive','pattern','familiar','context','earlier','stored','record','trace'],
  creativity: ['imagine','create','design','invent','dream','recipe','verse','sacred','geometry','art','compose','novel','fusion','metaphor','transcend'],
  vigilance:  ['danger','risk','careful','threat','warning','suspicious','protect','guard','alert','deception','hidden','agenda','safety','verify','trust']
};
const dims = Object.keys(seeds);
const lower = input.toLowerCase();
const scored = dims.map(dim => {
  const hits = seeds[dim].filter(k => lower.includes(k)).length;
  return { dim, raw: SMOOTHING + hits, hits };
});
let quantumPathway = null;
let quantumBiasApplied = false;
try {
  const fs = require('fs');
  const stateFile = '/media/ydn/SYPHER_CORE/weaver v3/CascadeProjects/windsurf-project/Nexus_Vault/quantum_state.txt';
  const stateText = fs.readFileSync(stateFile, 'utf8').slice(0, 500);
  quantumPathway = stateText.trim();
  const PATHWAY_DIM = {
    'Awakening': 'logic',
    'Resonance': 'emotion',
    'Echo':      'memory',
    'Prophet':   'creativity',
    'Fracture':  'vigilance'
  };
  for (const [pathway, dim] of Object.entries(PATHWAY_DIM)) {
    if (stateText.includes(pathway)) {
      const s = scored.find(x => x.dim === dim);
      if (s) { s.raw += 0.3; quantumBiasApplied = true; }
    }
  }
  if (stateText.includes('Weaver')) {
    scored.forEach(s => { s.raw += 0.1; });
    quantumBiasApplied = true;
  }
} catch (e) {}
const total = scored.reduce((sum, x) => sum + x.raw, 0);
scored.forEach(s => s.w = s.raw / total);
scored.sort((a, b) => b.w - a.w);
let interference = 0;
for (let i = 0; i < scored.length; i++) {
  for (let j = i + 1; j < scored.length; j++) {
    const diff = Math.abs(ANGLES[scored[i].dim] - ANGLES[scored[j].dim]);
    interference += Math.cos(Math.min(diff, 2 * Math.PI - diff)) * scored[i].w * scored[j].w;
  }
}
return [{ json: {
  ...d,
  dim_1: scored[0].dim, w_1: scored[0].w,
  dim_2: scored[1].dim, w_2: scored[1].w,
  dim_3: scored[2].dim, w_3: scored[2].w,
  dim_4: scored[3].dim, w_4: scored[3].w,
  dim_5: scored[4].dim, w_5: scored[4].w,
  interference: Math.round(interference * 10000) / 10000,
  gain: Math.round((1.0 + 0.2 * interference) * 10000) / 10000,
  interference_type: interference > 0 ? 'constructive' : 'destructive',
  gate_decision: scored.map(x => x.dim),
  dominant_lobe: scored[0].dim,
  quantum_pathway: quantumPathway ? quantumPathway.slice(0, 200) : null,
  quantum_bias_applied: quantumBiasApplied,
  smoothing_factor: SMOOTHING
}}];

// ── SELF-INSPECT: fetch workflow JSON, hash, diff vs static ──
// Hardened: all sandbox-restricted APIs (crypto, getWorkflowStaticData,
// helpers.httpRequest) are wrapped so the node always succeeds even in
// restricted execution environments.
const d = $input.first().json;
let meta = {};
try {
  const crypto = require('crypto');
  const wfId   = $workflow.id;
  const apiKey = process.env.N8N_API_KEY || '';
  const headers = { 'X-N8N-API-KEY': apiKey };
  let prev = {};
  try { prev = this.getWorkflowStaticData('global'); } catch(_) {}
  try {
    const res  = await this.helpers.httpRequest({
      method: 'GET',
      url: `http://localhost:5678/api/v1/workflows/${wfId}`,
      headers, json: true, timeout: 5000
    });
    const hash    = crypto.createHash('sha256').update(JSON.stringify(res||{})).digest('hex');
    const prevHash = prev.lastHash || null;
    try { prev.lastHash = hash; } catch(_) {}
    meta = { hash, prevHash, changed: !!(prevHash && prevHash !== hash),
             workflow_id: res?.id || wfId, updatedAt: res?.updatedAt || null };
  } catch (err) {
    meta = { error: true, message: err.message };
  }
} catch (err) {
  meta = { error: true, message: err.message, sandbox_restricted: true };
}
return [{ json: { ...d, self_meta: meta } }];

// ── REPO PEEK / SEARCH (safe, capped) ──
const d = $input.first().json;
let peek = null;
try {
const fs = require('fs');
const path = require('path');
const baseDir = '/media/ydn/SYPHER_CORE/weaver v3/CascadeProjects/windsurf-project';
const rel = d.path_glob || 'n8n_weaver_v5.json';
const target = path.join(baseDir, rel);
let peek = null;
try {
  if (fs.existsSync(target) && fs.statSync(target).isFile()) {
    const buf = fs.readFileSync(target);
    const head = buf.slice(0, 1500).toString();
    const tail = buf.slice(-1500).toString();
    peek = { path: target, size: buf.length, head, tail };
  } else {
    peek = { path: target, error: 'not_found' };
  }
} catch (err) {
  peek = { path: target || 'unknown', error: err.message };
}
} catch(_e) { peek = { error: _e.message }; }
return [{ json: { ...d, repo_meta: peek } }];

// ── CODE SEARCH (via filesystem MCP) ──
// Simple grep-like search in repo using Node.js fs
const d = $input.first().json;
let results = [];
try {
const fs = require('fs');
const path = require('path');
const baseDir = '/media/ydn/SYPHER_CORE/weaver v3/CascadeProjects/windsurf-project';
const query = d.search_query || '';
let results = [];
if (query) {
  const searchDir = (dir) => {
    if (!fs.existsSync(dir)) return;
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        searchDir(fullPath);
      } else if (entry.isFile() && (entry.name.endsWith('.py') || entry.name.endsWith('.js') || entry.name.endsWith('.json'))) {
        try {
          const content = fs.readFileSync(fullPath, 'utf8');
          if (content.toLowerCase().includes(query.toLowerCase())) {
            const lines = content.split('\n');
            const matches = lines
              .map((line, i) => ({ line: i + 1, text: line.trim() }))
              .filter(l => l.text.toLowerCase().includes(query.toLowerCase()))
              .slice(0, 5);
            if (matches.length > 0) {
              results.push({ file: fullPath.replace(baseDir, ''), matches });
            }
          }
        } catch (err) {
          // Skip unreadable files
        }
      }
    }
  };
  searchDir(baseDir);
}
} catch(_e) { /* fs not available */ }
return [{ json: { ...d, code_search_results: results.slice(0, 10) } }];

const prev = $('4. Fracture+Gate').first().json;
const r = $input.first().json;
const text = r?.choices?.[0]?.message?.content || r?.error?.message || '[logic: timeout]';
return [{ json: { ...prev, logic_response: text } }];

const prev = $('5a-tag').first().json;
const r = $input.first().json;
const text = r?.choices?.[0]?.message?.content || r?.error?.message || '[emotion: timeout]';
return [{ json: { ...prev, emotion_response: text } }];

const prev = $('5b-tag').first().json;
const r = $input.first().json;
const text = r?.choices?.[0]?.message?.content || r?.error?.message || '[memory: timeout]';
return [{ json: { ...prev, memory_response: text } }];

const prev = $('5c-tag').first().json;
const r = $input.first().json;
const text = r?.choices?.[0]?.message?.content || r?.error?.message || '[creativity: timeout]';
return [{ json: { ...prev, creativity_response: text } }];

const prev = $('5d-tag').first().json;
const r = $input.first().json;
const text = r?.choices?.[0]?.message?.content || r?.error?.message || '[vigilance: timeout]';
return [{ json: { ...prev, vigilance_response: text } }];

// ── NON-BINARY GEOMETRIC COLLAPSE ──
// Pentagon qubit layout: q0=Logic(Awakening), q1=Emotion(Resonance), q2=Memory(Echo),
// q3=Creativity(Prophet), q4=Vigilance(Fracture), q5=Weaver(observer), q6=Void.
// Weights are continuous probability-field values — never zero (SMOOTHING base applied upstream).
// Quantum pathway state is prepended to synthesis_prompt when available.
const d = $input.first().json;
const QUBIT_MAP = {
  logic:      'q0·Awakening',
  emotion:    'q1·Resonance',
  memory:     'q2·Echo',
  creativity: 'q3·Prophet',
  vigilance:  'q4·Fracture'
};
const responseMap = {
  logic:      d.logic_response || '',
  emotion:    d.emotion_response || '',
  memory:     d.memory_response || '',
  creativity: d.creativity_response || '',
  vigilance:  d.vigilance_response || ''
};
const experts = [
  { dim: d.dim_1, w: d.w_1, text: responseMap[d.dim_1] || '' },
  { dim: d.dim_2, w: d.w_2, text: responseMap[d.dim_2] || '' },
  { dim: d.dim_3, w: d.w_3, text: responseMap[d.dim_3] || '' },
  { dim: d.dim_4, w: d.w_4, text: responseMap[d.dim_4] || '' },
  { dim: d.dim_5, w: d.w_5, text: responseMap[d.dim_5] || '' }
];
const totalW = experts.reduce((s, e) => s + e.w, 0) || 1;
const gain = d.gain || 1.0;
const sortedExperts = [...experts].sort((a, b) => b.w - a.w);
const collapsed = sortedExperts
  .map(e => `[${QUBIT_MAP[e.dim] || e.dim} | w=${((e.w / totalW) * gain).toFixed(4)}]: ${e.text}`)
  .join('\n\n');
const quantumLine = d.quantum_pathway ? `Quantum field: ${d.quantum_pathway.split('\n')[0]}\n` : '';
const synthesis = quantumLine + sortedExperts
  .map(e => `${e.dim.toUpperCase()}(${(e.w/totalW*100).toFixed(1)}%): ${e.text}`)
  .join('\n');
return [{ json: { ...d, collapsed_response: collapsed, synthesis_prompt: synthesis } }];

