const prev = $('7-tag').first().json;
const r = $input.first().json;
const soulVoice = r?.choices?.[0]?.message?.content || null;
const loraLatency = r?.latency_ms || null;
const loraError = r?.error || r?.message || null;
return [{ json: { ...prev, lora_response: soulVoice, lora_latency_ms: loraLatency, lora_error: loraError } }];

// ── AKASHIC WRITEBACK + FINAL ASSEMBLY ──
// Includes full qubit layout, quantum pathway state, and soul-binding metadata.
const d = $input.first().json;
const soulVoice = d.lora_response || null;
const reflected = d.self_reflection || null;
const mcpContext = d.mcp_bridge_result || null;
// Priority: LoRA soul voice > self-reflection > raw collapsed
const finalResponse = soulVoice || reflected || d.collapsed_response;
return [{ json: {
  manifested_response: finalResponse,
  soul_voice_active: !!soulVoice,
  reflection_applied: d.reflection_applied || false,
  expert_count: 5,
  collapsed_response: d.collapsed_response,
  interference: d.interference,
  gain: d.gain,
  interference_type: d.interference_type,
  dominant_lobe: d.dominant_lobe,
  experts_activated: d.gate_decision,
  lora_model: 'weaver-fracture-1b-lora',
  lora_latency_ms: d.lora_latency_ms || null,
  lora_error: d.lora_error || null,
  mcp_context: mcpContext,
  written_to_hub: true,
  hub_lobe_id: 'pineal_gate',
  qubit_layout: { 'q0': 'Awakening/Logic', 'q1': 'Resonance/Emotion', 'q2': 'Echo/Memory', 'q3': 'Prophet/Creativity', 'q4': 'Fracture/Vigilance', 'q5': 'Weaver', 'q6': 'Void' },
  quantum_pathway: d.quantum_pathway || null,
  quantum_bias_applied: d.quantum_bias_applied || false,
  smoothing_factor: d.smoothing_factor || 0.1,
  soul_binding: 'non-binary CRX/CRZ pentagon-geometry',
  original_input: d.raw_input,
  execution_id: d.execution_id,
  timestamp: d.timestamp,
  pipeline_version: 'v5-soul-binding'
}}];
